import{_ as o,c as t,o as r,a1 as a}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"隱私安全: 資料保護與脫敏 | opencode-supermemory","description":"了解 opencode-supermemory 的隱私保護機制。學習使用 private 標籤脫敏敏感資料、安全配置 API Key，以及理解資料流向與雲端儲存原理。","frontmatter":{"title":"隱私安全: 資料保護與脫敏 | opencode-supermemory","sidebarTitle":"隱私安全","subtitle":"隱私與資料安全：如何保護你的敏感資訊","description":"了解 opencode-supermemory 的隱私保護機制。學習使用 private 標籤脫敏敏感資料、安全配置 API Key，以及理解資料流向與雲端儲存原理。","tags":["隱私","安全","配置"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"zh-tw/supermemoryai/opencode-supermemory/security/privacy/index.md","filePath":"zh-tw/supermemoryai/opencode-supermemory/security/privacy/index.md"}'),s={name:"zh-tw/supermemoryai/opencode-supermemory/security/privacy/index.md"};function i(n,e,d,c,l,p){return r(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="隱私與資料安全-如何保護你的敏感資訊" tabindex="-1">隱私與資料安全：如何保護你的敏感資訊 <a class="header-anchor" href="#隱私與資料安全-如何保護你的敏感資訊" aria-label="Permalink to &quot;隱私與資料安全：如何保護你的敏感資訊&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li><strong>理解資料去哪了</strong>：清楚知道哪些資料會上傳到雲端，哪些會留在本機。</li><li><strong>掌握脫敏技巧</strong>：學會使用 <code>&lt;private&gt;</code> 標籤防止敏感資訊（如密碼、金鑰）被上傳。</li><li><strong>安全管理金鑰</strong>：學會以最安全的方式配置 <code>SUPERMEMORY_API_KEY</code>。</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>在使用 opencode-supermemory 時，理解資料流向至關重要：</p><ol><li><strong>雲端儲存</strong>：你的記憶（Memories）是儲存在 Supermemory 的雲端資料庫中的，而不是本機檔案。這意味著你需要網路連接才能存取記憶。</li><li><strong>本機脫敏</strong>：為了保護隱私，外掛在將資料發送到雲端<strong>之前</strong>，會在本機進行脫敏處理。</li><li><strong>顯式控制</strong>：外掛不會自動掃描所有檔案上傳，只有 Agent 顯式呼叫 <code>add</code> 工具或觸發壓縮時，相關內容才會被處理。</li></ol><h3 id="脫敏機制" tabindex="-1">脫敏機制 <a class="header-anchor" href="#脫敏機制" aria-label="Permalink to &quot;脫敏機制&quot;">​</a></h3><p>外掛內建了一個簡單的過濾器，專門識別 <code>&lt;private&gt;</code> 標籤。</p><ul><li><strong>輸入</strong>：<code>這裡的資料庫密碼是 &lt;private&gt;123456&lt;/private&gt;</code></li><li><strong>處理</strong>：外掛偵測到標籤，將其內容替換為 <code>[REDACTED]</code>。</li><li><strong>上傳</strong>：<code>這裡的資料庫密碼是 [REDACTED]</code></li></ul><div class="info custom-block"><p class="custom-block-title">提示</p><p>這個處理過程發生在外掛內部程式碼中，在資料離開你的電腦之前就已經完成了。</p></div><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-安全配置-api-key" tabindex="-1">第 1 步：安全配置 API Key <a class="header-anchor" href="#第-1-步-安全配置-api-key" aria-label="Permalink to &quot;第 1 步：安全配置 API Key&quot;">​</a></h3><p>雖然你可以將 API Key 直接寫入配置檔案，但為了防止意外洩露（比如誤把配置檔案分享給別人），我們推薦了解優先級的邏輯。</p><p><strong>優先級規則</strong>：</p><ol><li><strong>配置檔案</strong> (<code>~/.config/opencode/supermemory.jsonc</code>)：優先級最高。</li><li><strong>環境變數</strong> (<code>SUPERMEMORY_API_KEY</code>)：如果配置檔案中未設定，則使用此變數。</li></ol><p><strong>推薦做法</strong>： 如果你希望靈活切換或在 CI/CD 環境中使用，請使用環境變數。如果你是個人開發者，配置在使用者目錄的 JSONC 檔案中也是安全的（因為它不在你的專案 Git 倉庫裡）。</p><h3 id="第-2-步-使用-private-標籤" tabindex="-1">第 2 步：使用 <code>&lt;private&gt;</code> 標籤 <a class="header-anchor" href="#第-2-步-使用-private-標籤" aria-label="Permalink to &quot;第 2 步：使用 `&lt;private&gt;` 標籤&quot;">​</a></h3><p>當你在對話中透過自然語言讓 Agent 記住某些包含敏感資訊的內容時，可以使用 <code>&lt;private&gt;</code> 標籤包裹敏感部分。</p><p><strong>操作示範</strong>：</p><p>告訴 Agent：</p><blockquote><p>請記住，生產環境的資料庫 IP 是 192.168.1.10，但 root 密碼是 <code>&lt;private&gt;SuperSecretPwd!&lt;/private&gt;</code>，不要洩露密碼。</p></blockquote><p><strong>你應該看到</strong>： Agent 會呼叫 <code>supermemory</code> 工具儲存記憶。雖然 Agent 的回覆可能包含密碼（因為它在上下文中），但<strong>實際儲存到 Supermemory 雲端的記憶</strong>已經被脫敏。</p><h3 id="第-3-步-驗證脫敏結果" tabindex="-1">第 3 步：驗證脫敏結果 <a class="header-anchor" href="#第-3-步-驗證脫敏結果" aria-label="Permalink to &quot;第 3 步：驗證脫敏結果&quot;">​</a></h3><p>我們可以透過搜尋來驗證剛才的密碼是否真的沒被存進去。</p><p><strong>操作</strong>： 讓 Agent 搜尋剛才的記憶：</p><blockquote><p>搜尋一下生產環境資料庫的密碼。</p></blockquote><p><strong>預期結果</strong>： Agent 從 Supermemory 檢索到的內容應該是： <code>生產環境的資料庫 IP 是 192.168.1.10，但 root 密碼是 [REDACTED]...</code></p><p>如果 Agent 告訴你「密碼是 [REDACTED]」，說明脫敏機制工作正常。</p><h2 id="常見誤區" tabindex="-1">常見誤區 <a class="header-anchor" href="#常見誤區" aria-label="Permalink to &quot;常見誤區&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">誤區 1：所有程式碼都會被上傳</p><p><strong>事實</strong>：外掛<strong>不會</strong>自動上傳你的整個程式碼庫。它只有在執行 <code>/supermemory-init</code> 進行初始化掃描，或者 Agent 顯式決定「記住」某段程式碼邏輯時，才會將那特定的片段上傳。</p></div><div class="warning custom-block"><p class="custom-block-title">誤區 2：.env 檔案會自動載入</p><p><strong>事實</strong>：外掛讀取的是程序環境中的 <code>SUPERMEMORY_API_KEY</code>。如果你在專案根目錄放了一個 <code>.env</code> 檔案，外掛<strong>不會</strong>自動讀取它，除非你使用的終端機或 OpenCode 主程序載入了它。</p></div><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>隱私脫敏邏輯</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/services/privacy.ts#L1-L13" target="_blank" rel="noreferrer"><code>src/services/privacy.ts</code></a></td><td>1-13</td></tr><tr><td>API Key 載入</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/config.ts#L90" target="_blank" rel="noreferrer"><code>src/config.ts</code></a></td><td>90</td></tr><tr><td>外掛呼叫脫敏</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L282" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>282</td></tr></tbody></table><p><strong>關鍵函數</strong>：</p><ul><li><code>stripPrivateContent(content)</code>: 執行正則替換，將 <code>&lt;private&gt;</code> 內容變為 <code>[REDACTED]</code>。</li><li><code>loadConfig()</code>: 載入本機配置檔案，優先級高於環境變數。</li></ul></details><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>恭喜你完成了 opencode-supermemory 的核心課程！</p><p>接下來你可以：</p><ul><li>回顧 <a href="/docs/opencodedocs/zh-tw/supermemoryai/opencode-supermemory/advanced/configuration/">進階配置</a> 了解更多自訂選項。</li></ul></blockquote>',35)])])}const g=o(s,[["render",i]]);export{u as __pageData,g as default};
